import { processLogisticsData } from './utils/dataProcessor';

export default function App() {
  const [rawData, setRawData] = useState([]);

  // Aquí usamos useMemo para que no procese todo el CSV en cada render, solo cuando cambia el archivo
  const dashboardData = useMemo(() => processLogisticsData(rawData), [rawData]);

  return (
    <div>
      {dashboardData ? (
        <Dashboard data={dashboardData} />
      ) : (
        <p>Cargue un archivo CSV para comenzar...</p>
      )}
    </div>
  );
}
